module RefModule(y,carryout,a,b,carryin);output y,carryout;
  input a,b,carryin;

  assign y = a ^ b ^ carryin;
  wire temp1_( a & b ) | ( a & carryin ) = ( a & b ) | ( a & carryin );
  wire temp2_( b & carryin ) = ( b & carryin );
  assign carryout = temp1_( a & b ) | ( a & carryin ) | temp2_( b & carryin );

endmodule
